#include<bits/stdc++.h>
using namespace std;
int read()
{
    int x=0,f=1;
    char ch=getchar();
    while(!isdigit(ch))
    {
        if(ch=='-')
        {
            f=-1;
        }
        ch=getchar();
    }
    while(isdigit(ch))
    {
        x=x*10+ch-'0';
        ch=getchar();
    }
    return x*f;
}
int a[1000010],b[1000010],c[1000010];
map<int,int> mp;
int main()
{
    int n=read(),min1=INT_MAX;
    for(int i=1;i<=n;i++)
    {
        a[i]=read();
    }
    sort(a+1,a+1+n);
    for(int i=1;i<=n;i++)
    {
        b[i]=read();
    }
    int x=a[1];
    stack<int> s;
    int i=1;
    while(!(x>a[n]&&s.empty()))
    {
        while(a[i]==x)
        {
            s.push(i);
            i++;
        }
        if(s.empty()&&x<a[i])
        {
            x=a[i];
            continue;
        }
        if(!s.empty())
        {
            int t=s.top();
            if(x!=t)
            {
                c[t]=x-a[t];
            }
            s.pop();
            x++;
        }
    }
    unsigned long long ans=0;
    sort(c+1,c+1+n);
    sort(b+1,b+1+n);
    for(int i=1;i<=n;i++)
    {
        ans+=1llu*c[n-i+1]*b[i];
    }
    printf("%llu",ans);
    return 0;
}
